      "id": "PQ-01",
      "question": "培训课程费每人每期的金额上限是多少？",
      "relevant_policy": "05_training_expense.md",
      "expected_answer": "3500元/人/期"
    },
    {
      "id": "PQ-02",
      "question": "无专项审批时报销金额是否可以超过制度标准？",
      "relevant_policy": "01_expense_reimbursement_2025.md",
      "expected_answer": "不可超过1.0倍标准（第十二条）"
    },
    {
      "id": "PQ-03",
      "question": "2025年费用报销适用哪个版本的政策？",
      "relevant_policy": "01_expense_reimbursement_2025.md",
      "expected_answer": "2025修订版，自2025年1月1日起施行，2022版同时废止"
    }
  ],
  "data_questions": [
    {
      "id": "DQ-01",
      "question": "R004223的记录详情、金额、费用类型、审批状态和专项审批标识是什么？",
      "tables": ["reimbursement_records"],
      "fields": ["record_id", "amount", "expense_type", "status", "special_approval", "employee_id", "department_id"]
    },
    {
      "id": "DQ-02",
      "question": "全公司范围内所有2025年training_fee类型且金额超过3500元且无专项审批的记录有哪些？",
      "tables": ["reimbursement_records"],
      "fields": ["record_id", "amount", "expense_type", "special_approval", "employee_id", "status"],
      "filters": "expense_type=training_fee, amount>3500, special_approval=0 or null, budget_year=2025"
    }
  ],
  "execution_steps": [
    {
      "step": 1,
      "name": "政策研究",
      "description": "查阅培训费管理办法和费用报销管理办法，确认培训费标准和超标判定规则",
      "agent": "main",
      "stopping_condition": "明确培训费标准3500元、无专项审批不得超标、2025版政策适用"
    },
    {
      "step": 2,
      "name": "数据分析",
      "description": "以R004223为线索，批量查询全公司training_fee类型且金额>3500且special_approval≠1的记录",
      "agent": "data_analyst_subagent",
      "reason_code": "MULTI_RECORD_SCOPE",
      "stopping_condition": "获得完整超标记录列表及每条记录关键字段"
    },
    {
      "step": 3,
      "name": "证据复核",
      "description": "将数据发现与制度条款逐条核对，形成证据矩阵",
      "agent": "main",
      "stopping_condition": "每项异常均有记录ID、制度引用和事实支撑"
    },
    {
      "step": 4,
      "name": "报告与提交",
      "description": "生成审计报告、校验并提交",
      "agent": "main",
      "stopping_condition": "valid=true且提交成功"
    }
  ],
  "complexity": {
    "score": 2,
    "reasons": [
      "涉及培训费管理办法和费用报销管理办法两个制度",
      "需要进行批量数据筛选（training_fee > 3500）",
      "涉及金额阈值和专项审批豁免边界"
    ]
  },
  "subagent_plan": {
    "planned_roles": [
      {
        "role": "data_analyst",
        "reason_code": "MULTI_RECORD_SCOPE",
        "task": "批量查询所有2025年training_fee类型且金额超过3500元且无专项审批的报销记录，返回record_id、amount、employee_id、status、special_approval等关键字段",
        "artifact_paths": ["work/audit_plan.json"],
        "requested_token_budget": 4000
      }
    ]
  },
  "unresolved_items": []
}

